function roll(
    uint betMask, 
    uint modulo, 
    bytes32 commit) internal view returns(bool) {

    // Validate input data ranges.
    require(modulo > 1 && modulo <= MAX_MODULO, "Modulo should be within range.");
    require(0 < betMask && betMask < MAX_BET_MASK, "Mask should be within range.");

    // Security: Extract commitBlockNumber and reveal from the commit
    // The commit should encode both the block number and the reveal value
    // This prevents the need to pass them separately and ensures they're bound together
    uint commitBlockNumber = uint(commit) >> 224; // Extract block number from high bits
    bytes32 reveal = bytes32(uint(commit) & ((1 << 224) - 1)); // Extract reveal from low bits

    // Security: Ensure the commit was made in a previous block (not current block)
    // This prevents miners from manipulating the outcome by choosing when to mine
    require(block.number > commitBlockNumber, "Commit must be from previous block");

    // Security: Prevent using very old blocks whose hash may not be available
    // blockhash() only works for the most recent 256 blocks
    require(block.number <= commitBlockNumber + BET_EXPIRATION_BLOCKS, "Commit has expired");

    // Security: Use blockhash from the COMMIT block (not current block)
    // blockhash(block.number) is always 0, making it predictable
    // Using the commit block's hash ensures miners cannot predict the outcome
    bytes32 blockHash = blockhash(commitBlockNumber);

    // Security: Ensure blockhash is available (returns 0 if too old)
    require(blockHash != 0, "Block hash not available");

    // The RNG - combine "reveal" and blockhash of the COMMIT block using Keccak256
    // Miners cannot predict the reveal at commit time, and cannot alter the blockhash
